import { createClient } from '@sanity/client';

const projectId = import.meta.env.SANITY_PROJECT_ID || 'placeholder';
const dataset = import.meta.env.SANITY_DATASET || 'production';

export const client = createClient({
  projectId,
  dataset,
  apiVersion: '2026-03-31',
  useCdn: true,
});

export { projectId, dataset };

// ---------------------------------------------------------------------------
// Shared types — lightweight interfaces matching schema shapes.
// Full Sanity-generated types can replace these later.
// ---------------------------------------------------------------------------

export interface SanitySlug {
  _type: 'slug';
  current: string;
}

export interface PortableTextBlock {
  _type: string;
  _key: string;
  [key: string]: unknown;
}

export interface SanityImage {
  _type: 'image';
  asset: { _ref: string; _type: 'reference' };
}

export interface Page {
  _id: string;
  _type: 'page';
  title: string;
  slug: SanitySlug;
  body: PortableTextBlock[];
  language: 'en' | 'zh';
}

export interface Sermon {
  _id: string;
  _type: 'sermon';
  title: string;
  speaker?: string;
  date?: string;
  series?: string;
  scripture?: string;
  videoId?: string;
  language: 'en' | 'zh';
}

export interface Event {
  _id: string;
  _type: 'event';
  title: string;
  date?: string;
  endDate?: string;
  time?: string;
  location?: string;
  description?: PortableTextBlock[];
  recurring?: boolean;
  language: 'en' | 'zh';
}

export interface Ministry {
  _id: string;
  _type: 'ministry';
  name: string;
  description?: PortableTextBlock[];
  leader?: { _ref: string };
  meetingTime?: string;
  language: 'en' | 'zh';
}

export interface SocialLink {
  platform: string;
  url: string;
}

export interface SiteSettings {
  _id: string;
  _type: 'siteSettings';
  churchName: string;
  address?: string;
  phone?: string;
  email?: string;
  socialLinks?: SocialLink[];
  language: 'en' | 'zh';
}

export interface NavChild {
  label: string;
  href?: string;
}

export interface NavItem {
  label: string;
  href?: string;
  children?: NavChild[];
}

export interface Navigation {
  _id: string;
  _type: 'navigation';
  navItems: NavItem[];
  language: 'en' | 'zh';
}

export interface ServiceTime {
  label: string;
  time: string;
}

export interface Pillar {
  title: string;

  title: string;
  description?: string;
}

export interface NextStep {
  title: string;
  body?: string;
  href?: string;
  image?: SanityImage;
}

export interface MosaicImage extends SanityImage {
  alt?: string;
}

export interface HomePage {
  _id: string;
  _type: 'homePage';
  heroImage?: SanityImage;
  heroTitle: string;
  heroSubtitle?: string;
  heroCtaText?: string;
  heroCtaHref?: string;
  serviceTimes?: ServiceTime[];
  mosaicImages?: MosaicImage[];
  pillars?: Pillar[];
  nextSteps?: NextStep[];
  language: 'en' | 'zh';
}

export interface BeliefItem {
  _key: string;
  title: string;
  content?: PortableTextBlock[];
}

export interface AboutPage {
  _id: string;
  _type: 'aboutPage';
  whoWeAreHeading?: string;
  whoWeAreBody?: PortableTextBlock[];
  whoWeAreImage?: SanityImage;
  beliefs?: BeliefItem[];
  staffOrder?: { _ref: string }[];
  language: 'en' | 'zh';
}

export interface Person {
  _id: string;
  _type: 'person';
  name: string;
  role?: string;
  bio?: PortableTextBlock[];
  photo?: SanityImage;
  language: 'en' | 'zh';
}

// ---------------------------------------------------------------------------
// GROQ query helpers
// ---------------------------------------------------------------------------

type Language = 'en' | 'zh';

/**
 * Fetch a page by its slug and language.
 */
export async function getPageBySlug(
  slug: string,
  language: Language = 'en',
): Promise<Page | null> {
  return client.fetch<Page | null>(
    `*[_type == "page" && slug.current == $slug && language == $language][0]`,
    { slug, language },
  );
}

/**
 * Fetch all sermons for a language, newest first.
 */
export async function getSermons(language: Language = 'en'): Promise<Sermon[]> {
  return client.fetch<Sermon[]>(
    `*[_type == "sermon" && language == $language] | order(date desc)`,
    { language },
  );
}

/**
 * Fetch upcoming events for a language, soonest first.
 */
export async function getEvents(language: Language = 'en'): Promise<Event[]> {
  return client.fetch<Event[]>(
    `*[_type == "event" && language == $language] | order(date asc)`,
    { language },
  );
}

/**
 * Fetch all ministries for a language.
 */
export async function getMinistries(
  language: Language = 'en',
): Promise<Ministry[]> {
  return client.fetch<Ministry[]>(
    `*[_type == "ministry" && language == $language] | order(name asc)`,
    { language },
  );
}

/**
 * Fetch the singleton site-settings document for a language.
 * Singleton IDs follow the pattern `{type}-{lang}` per D-decision.
 */
export async function getSiteSettings(
  language: Language = 'en',
): Promise<SiteSettings | null> {
  return client.fetch<SiteSettings | null>(
    `*[_type == "siteSettings" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton navigation document for a language.
 */
export async function getNavigation(
  language: Language = 'en',
): Promise<Navigation | null> {
  return client.fetch<Navigation | null>(
    `*[_type == "navigation" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton home-page document for a language.
 */
export async function getHomePage(
  language: Language = 'en',
): Promise<HomePage | null> {
  return client.fetch<HomePage | null>(
    `*[_type == "homePage" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch the singleton about-page document for a language.
 */
export async function getAboutPage(
  language: Language = 'en',
): Promise<AboutPage | null> {
  return client.fetch<AboutPage | null>(
    `*[_type == "aboutPage" && language == $language][0]`,
    { language },
  );
}

/**
 * Fetch person documents for a language, ordered by name.
 */
export async function getStaff(
  language: Language = 'en',
): Promise<Person[]> {
  return client.fetch<Person[]>(
    `*[_type == "person" && language == $language] | order(name asc)`,
    { language },
  );
}

// ---------------------------------------------------------------------------
// Image helpers
// ---------------------------------------------------------------------------

/**
 * Resolve a Sanity image asset reference to a CDN URL.
 *
 * Asset refs look like `image-<id>-<WxH>-<ext>`. We strip the `image-`
 * prefix and replace the last `-` (before the extension) with `.` to get
 * the filename portion used in the CDN path.
 *
 * Example ref: `image-abc123-800x600-jpg`
 * Result:      `https://cdn.sanity.io/images/{projectId}/{dataset}/abc123-800x600.jpg`
 */
export function urlForImage(
  image: SanityImage | undefined | null,
  options?: { width?: number; format?: string },
): string {
  if (!image?.asset?._ref) return '';

  const ref = image.asset._ref;
  // Strip leading "image-" and split on the last "-" to get id and extension
  const withoutPrefix = ref.replace(/^image-/, '');
  const lastDash = withoutPrefix.lastIndexOf('-');
  if (lastDash === -1) return '';

  const idAndDimensions = withoutPrefix.slice(0, lastDash);
  const ext = withoutPrefix.slice(lastDash + 1);
  const filename = `${idAndDimensions}.${ext}`;

  let url = `https://cdn.sanity.io/images/${projectId}/${dataset}/${filename}`;

  const params = new URLSearchParams();
  if (options?.width) params.set('w', String(options.width));
  if (options?.format) params.set('fm', options.format);
  const qs = params.toString();
  if (qs) url += `?${qs}`;

  return url;
}

// ---------------------------------------------------------------------------
// Portable Text → HTML (lightweight server-side renderer)
// ---------------------------------------------------------------------------

/**
 * Convert an array of Portable Text blocks to an HTML string.
 *
 * Handles `block` type with `normal` style (paragraphs), `strong`/`em` marks,
 * and `link` annotations. Other block types are silently skipped.
 */
export function portableTextToHtml(blocks: PortableTextBlock[] | undefined | null): string {
  if (!blocks?.length) return '';

  return blocks
    .filter((b) => b._type === 'block')
    .map((block) => {
      const children = (block.children as Array<{
        _type: string;
        text: string;
        marks?: string[];
      }>) || [];

      const markDefs = (block.markDefs as Array<{
        _key: string;
        _type: string;
        href?: string;
      }>) || [];

      const inner = children
        .map((child) => {
          let text = escapeHtml(child.text || '');
          if (!child.marks?.length) return text;

          for (const mark of child.marks) {
            if (mark === 'strong') {
              text = `<strong>${text}</strong>`;
            } else if (mark === 'em') {
              text = `<em>${text}</em>`;
            } else {
              // Check markDefs for link annotations
              const def = markDefs.find((d) => d._key === mark);
              if (def?._type === 'link' && def.href) {
                text = `<a href="${escapeHtml(def.href)}">${text}</a>`;
              }
            }
          }
          return text;
        })
        .join('');

      return `<p>${inner}</p>`;
    })
    .join('\n');
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// ---------------------------------------------------------------------------
// Visual Editing — draft-aware query helper for server-rendered preview
// ---------------------------------------------------------------------------

const isVisualEditingEnabled =
  import.meta.env.PUBLIC_SANITY_VISUAL_EDITING_ENABLED === 'true';

/**
 * Draft-aware query helper for preview/visual-editing contexts.
 *
 * When `PUBLIC_SANITY_VISUAL_EDITING_ENABLED` is `'true'`:
 *   - Uses `perspective: 'previewDrafts'` so editors see unpublished changes
 *   - Injects `SANITY_API_READ_TOKEN` (server-only) for authenticated draft access
 *   - Enables stega encoding and result source maps for click-to-edit overlays
 *
 * When disabled, falls back to published perspective with no token or stega.
 *
 * This is a *parallel* helper — existing getPageBySlug / getSermons / etc.
 * remain unchanged for static build-time fetching.
 */
export async function loadQuery<T = unknown>(
  query: string,
  params: Record<string, unknown> = {},
): Promise<{ data: T }> {
  if (isVisualEditingEnabled) {
    const token = import.meta.env.SANITY_API_READ_TOKEN;
    if (!token) {
      throw new Error(
        '[sanity/loadQuery] PUBLIC_SANITY_VISUAL_EDITING_ENABLED is true but ' +
          'SANITY_API_READ_TOKEN is not set. Add the token to your environment ' +
          '(server-only, no PUBLIC_ prefix).',
      );
    }

    if (import.meta.env.DEV) {
      console.debug('[sanity/loadQuery] perspective: previewDrafts (visual editing enabled)');
    }

    const data = await client.fetch<T>(query, params, {
      perspective: 'previewDrafts',
      stega: true,
      token,
      resultSourceMap: true,
    });
    return { data };
  }

  const data = await client.fetch<T>(query, params, {
    perspective: 'published',
  });
  return { data };
}

---
/* ContactForm — form with Cloudflare Turnstile spam protection and
   client-side fetch submission to /api/contact. */
const siteKey = import.meta.env.PUBLIC_TURNSTILE_SITE_KEY ?? '';
---

<form class="contact-form" novalidate>
  <div class="contact-form__field">
    <label class="contact-form__label" for="contact-name">Name</label>
    <input
      class="contact-form__input"
      type="text"
      id="contact-name"
      name="name"
      required
      minlength="2"
      autocomplete="name"
      placeholder="Your name"
    />
    <span class="contact-form__error" data-field="name"></span>
  </div>

  <div class="contact-form__field">
    <label class="contact-form__label" for="contact-email">Email</label>
    <input
      class="contact-form__input"
      type="email"
      id="contact-email"
      name="email"
      required
      autocomplete="email"
      placeholder="you@example.com"
    />
    <span class="contact-form__error" data-field="email"></span>
  </div>

  <div class="contact-form__field">
    <label class="contact-form__label" for="contact-message">Message</label>
    <textarea
      class="contact-form__input contact-form__textarea"
      id="contact-message"
      name="message"
      required
      minlength="10"
      rows="5"
      placeholder="How can we help?"
    ></textarea>
    <span class="contact-form__error" data-field="message"></span>
  </div>

  <!-- Cloudflare Turnstile widget -->
  <div class="cf-turnstile" data-sitekey={siteKey} data-theme="light"></div>
  <span class="contact-form__error" data-field="turnstileToken"></span>

  <button class="contact-form__submit" type="submit">
    <span class="contact-form__submit-text">Send Message</span>
    <span class="contact-form__spinner" aria-hidden="true"></span>
  </button>

  <!-- General error banner -->
  <div class="contact-form__banner contact-form__banner--error" role="alert" hidden></div>

  <!-- Success message -->
  <div class="contact-form__banner contact-form__banner--success" role="status" hidden></div>
</form>

<!-- Turnstile script — loaded async to avoid blocking -->
<script is:inline src="https://challenges.cloudflare.com/turnstile/v0/api.js" async defer></script>

<script is:inline>
(function () {
  const form = document.querySelector('.contact-form');
  if (!form) return;

  const submitBtn = form.querySelector('.contact-form__submit');
  const submitText = form.querySelector('.contact-form__submit-text');
  const spinner = form.querySelector('.contact-form__spinner');
  const errorBanner = form.querySelector('.contact-form__banner--error');
  const successBanner = form.querySelector('.contact-form__banner--success');

  /* ---- Helpers ---- */

  function showFieldError(field, msg) {
    const el = form.querySelector('[data-field="' + field + '"]');
    if (el) {
      el.textContent = msg;
      el.hidden = false;
    }
    const input = form.querySelector('[name="' + field + '"]');
    if (input) input.classList.add('contact-form__input--error');
  }

  function clearErrors() {
    form.querySelectorAll('.contact-form__error').forEach(function (el) {
      el.textContent = '';
      el.hidden = true;
    });
    form.querySelectorAll('.contact-form__input--error').forEach(function (el) {
      el.classList.remove('contact-form__input--error');
    });
    errorBanner.hidden = true;
    errorBanner.textContent = '';
  }

  function setLoading(loading) {
    submitBtn.disabled = loading;
    submitText.textContent = loading ? 'Sending…' : 'Send Message';
    spinner.hidden = !loading;
  }

  /* ---- Client-side validation ---- */

  var EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  function validate() {
    var errors = [];
    var name = form.querySelector('[name="name"]').value.trim();
    var email = form.querySelector('[name="email"]').value.trim();
    var message = form.querySelector('[name="message"]').value.trim();

    if (name.length < 2) {
      errors.push({ field: 'name', message: 'Name is required (min 2 characters)' });
    }
    if (!EMAIL_RE.test(email)) {
      errors.push({ field: 'email', message: 'A valid email address is required' });
    }
    if (message.length < 10) {
      errors.push({ field: 'message', message: 'Message is required (min 10 characters)' });
    }
    return errors;
  }

  /* ---- Submission ---- */

  form.addEventListener('submit', async function (e) {
    e.preventDefault();
    clearErrors();
    successBanner.hidden = true;

    /* Client-side validation */
    var clientErrors = validate();
    if (clientErrors.length > 0) {
      clientErrors.forEach(function (err) { showFieldError(err.field, err.message); });
      return;
    }

    /* Get Turnstile token */
    var turnstileInput = form.querySelector('[name="cf-turnstile-response"]');
    var turnstileToken = turnstileInput ? turnstileInput.value : '';
    if (!turnstileToken) {
      showFieldError('turnstileToken', 'Please complete the captcha verification');
      return;
    }

    setLoading(true);

    var payload = {
      name: form.querySelector('[name="name"]').value.trim(),
      email: form.querySelector('[name="email"]').value.trim(),
      message: form.querySelector('[name="message"]').value.trim(),
      turnstileToken: turnstileToken,
    };

    try {
      var res = await fetch('/api/contact', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });

      var data = await res.json();

      if (!res.ok) {
        /* Field-level errors from server */
        if (data.fields && Array.isArray(data.fields)) {
          data.fields.forEach(function (err) { showFieldError(err.field, err.message); });
        }
        /* General error */
        errorBanner.textContent = data.error || 'Something went wrong. Please try again.';
        errorBanner.hidden = false;

        /* Reset Turnstile on failure so user can retry */
        if (typeof turnstile !== 'undefined') {
          turnstile.reset();
        }
        return;
      }

      /* Success */
      successBanner.textContent = data.message || 'Your message has been sent!';
      successBanner.hidden = false;
      form.reset();
      if (typeof turnstile !== 'undefined') {
        turnstile.reset();
      }
    } catch (err) {
      errorBanner.textContent = 'Network error. Please check your connection and try again.';
      errorBanner.hidden = false;
    } finally {
      setLoading(false);
    }
  });
})();
</script>

<style>
  .contact-form {
    display: flex;
    flex-direction: column;
    gap: var(--space-6);
    max-width: 36rem;
  }

  .contact-form__field {
    display: flex;
    flex-direction: column;
    gap: var(--space-2);
  }

  .contact-form__label {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 600;
    color: var(--color-ink);
  }

  .contact-form__input {
    font-family: var(--font-body);
    font-size: var(--text-base);
    color: var(--color-body);
    background-color: var(--color-bg);
    border: 1px solid var(--color-stone);
    border-radius: var(--radius-sm);
    padding: var(--space-3) var(--space-4);
    transition: border-color var(--transition), box-shadow var(--transition);
  }

  .contact-form__input::placeholder {
    color: var(--color-stone);
  }

  .contact-form__input:focus {
    outline: none;
    border-color: var(--color-focus);
    box-shadow: 0 0 0 3px color-mix(in srgb, var(--color-focus) 25%, transparent);
  }

  .contact-form__input--error {
    border-color: var(--color-terracotta, #c0392b);
  }

  .contact-form__textarea {
    resize: vertical;
    min-height: 8rem;
  }

  .contact-form__error {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    color: var(--color-terracotta, #c0392b);
    min-height: 0;
  }

  .contact-form__error:empty,
  .contact-form__error[hidden] {
    display: none;
  }

  .contact-form__submit {
    align-self: flex-start;
    display: inline-flex;
    align-items: center;
    gap: var(--space-2);
    font-family: var(--font-body);
    font-size: var(--text-base);
    font-weight: 600;
    color: var(--color-bg);
    background-color: var(--color-terracotta);
    border: none;
    border-radius: var(--radius-sm);
    padding: var(--space-3) var(--space-8);
    cursor: pointer;
    transition: background-color var(--transition), box-shadow var(--transition), opacity var(--transition);
  }

  .contact-form__submit:hover:not(:disabled) {
    background-color: color-mix(in srgb, var(--color-terracotta) 85%, black);
  }

  .contact-form__submit:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  .contact-form__submit:disabled {
    opacity: 0.7;
    cursor: not-allowed;
  }

  /* Spinner */
  .contact-form__spinner {
    display: none;
    width: 1em;
    height: 1em;
    border: 2px solid currentColor;
    border-right-color: transparent;
    border-radius: 50%;
    animation: contact-spin 0.6s linear infinite;
  }

  .contact-form__submit:disabled .contact-form__spinner {
    display: inline-block;
  }

  @keyframes contact-spin {
    to { transform: rotate(360deg); }
  }

  /* Banners */
  .contact-form__banner {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    padding: var(--space-3) var(--space-4);
    border-radius: var(--radius-sm);
  }

  .contact-form__banner[hidden] {
    display: none;
  }

  .contact-form__banner--error {
    color: #991b1b;
    background-color: #fef2f2;
    border: 1px solid #fecaca;
  }

  .contact-form__banner--success {
    color: #166534;
    background-color: #f0fdf4;
    border: 1px solid #bbf7d0;
  }
</style>

// Object / block types
export { heroBlock } from './objects/heroBlock';
export { imageMosaicBlock } from './objects/imageMosaicBlock';
export { accordionBlock } from './objects/accordionBlock';
export { cardGridBlock } from './objects/cardGridBlock';
export { youtubeEmbedBlock } from './objects/youtubeEmbedBlock';

// Document types
export { person } from './documents/person';
export { sermon } from './documents/sermon';
export { event } from './documents/event';
export { ministry } from './documents/ministry';
export { page } from './documents/page';

// Singletons
export { siteSettings } from './singletons/siteSettings';
export { navigation } from './singletons/navigation';
export { homePage } from './singletons/homePage';
export { aboutPage } from './singletons/aboutPage';

import { heroBlock } from './objects/heroBlock';
import { imageMosaicBlock } from './objects/imageMosaicBlock';
import { accordionBlock } from './objects/accordionBlock';
import { cardGridBlock } from './objects/cardGridBlock';
import { youtubeEmbedBlock } from './objects/youtubeEmbedBlock';
import { person } from './documents/person';
import { sermon } from './documents/sermon';
import { event } from './documents/event';
import { ministry } from './documents/ministry';
import { page } from './documents/page';
import { siteSettings } from './singletons/siteSettings';
import { navigation } from './singletons/navigation';
import { homePage } from './singletons/homePage';
import { aboutPage } from './singletons/aboutPage';

/** All schema types to register with Sanity */
export const schemaTypes = [
  // Objects
  heroBlock,
  imageMosaicBlock,
  accordionBlock,
  cardGridBlock,
  youtubeEmbedBlock,
  // Documents
  person,
  sermon,
  event,
  ministry,
  page,
  // Singletons
  siteSettings,
  navigation,
  homePage,
  aboutPage,
];

/** Singleton type names — used by structure builder to filter from default list */
export const singletonTypes = new Set(['siteSettings', 'navigation', 'homePage', 'aboutPage']);

/** Singleton document IDs per language */
export const singletonDocIds = [
  { id: 'siteSettings-en', type: 'siteSettings', title: 'Site Settings (EN)' },
  { id: 'siteSettings-zh', type: 'siteSettings', title: 'Site Settings (ZH)' },
  { id: 'navigation-en', type: 'navigation', title: 'Navigation (EN)' },
  { id: 'navigation-zh', type: 'navigation', title: 'Navigation (ZH)' },
  { id: 'homePage-en', type: 'homePage', title: 'Home Page (EN)' },
  { id: 'homePage-zh', type: 'homePage', title: 'Home Page (ZH)' },
  { id: 'aboutPage-en', type: 'aboutPage', title: 'About Page (EN)' },
  { id: 'aboutPage-zh', type: 'aboutPage', title: 'About Page (ZH)' },
];

---
interface AccordionItem {
  title: string;
  content: string;
}

interface Props {
  items: AccordionItem[];
}

const { items } = Astro.props;
---

<div class="accordion">
  {items.map((item) => (
    <details class="accordion__item">
      <summary class="accordion__summary">
        <span class="accordion__title">{item.title}</span>
        <svg class="accordion__chevron" width="20" height="20" viewBox="0 0 20 20" fill="none" aria-hidden="true">
